// 1. Define entity
public class Product
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public bool IsActive { get; set; } = true;
}

// 2. DbContext
public class AppDbContext : DbContext
{
    public AppDbContext(DbContextOptions<AppDbContext> opts) : base(opts) {}
    public DbSet<Product> Products => Set<Product>();
}

// 3. CRUD in a service
public class ProductService(AppDbContext db)
{
    public async Task<List<Product>> GetAllAsync() =>
        await db.Products.Where(p => p.IsActive).ToListAsync();

    public async Task CreateAsync(Product p)
    {
        db.Products.Add(p);
        await db.SaveChangesAsync();
    }
}

// Value type — copy on assignment
int a = 10;
int b = a;   // b is a copy
b = 20;      // a is still 10 ✓

// Reference type — reference copied, same object
var list1 = new List<int> { 1, 2, 3 };
var list2 = list1;  // both point to same list!
list2.Add(4);
Console.WriteLine(list1.Count);  // 4 — also changed!

// String is a special reference type — immutable
string s1 = "hello";
string s2 = s1;
s2 += " world";  // creates a NEW string — s1 unchanged ✓

// Registration in Program.cs
builder.Services.AddSingleton<IEmailSender, SmtpEmailSender>();
builder.Services.AddScoped<IOrderService, OrderService>();
builder.Services.AddTransient<IValidator<OrderDto>, OrderValidator>();

// Primary constructor injection (C# 12 / .NET 8+)
public class OrderService(AppDbContext db, IEmailSender email) : IOrderService
{
    public async Task PlaceOrderAsync(OrderDto dto)
    {
        var order = dto.ToEntity();
        db.Orders.Add(order);
        await db.SaveChangesAsync();
        await email.SendAsync(dto.CustomerEmail, "Order Confirmed", $"Order #{order.Id}");
    }
}

// Program.cs — middleware order matters!
var app = builder.Build();

app.UseExceptionHandler("/error");  // 1. Catch errors from all below
app.UseHttpsRedirection();          // 2. HTTPS redirect
app.UseStaticFiles();               // 3. Static files
app.UseRouting();                   // 4. Must be before Auth
app.UseAuthentication();            // 5. Auth — after Routing
app.UseAuthorization();
app.MapControllers();               // 6. Endpoints last

// Custom middleware
app.Use(async (context, next) => {
    Console.WriteLine($"→ {context.Request.Path}");
    await next(context);
    Console.WriteLine($"← {context.Response.StatusCode}");
});

