// ❌ IEnumerable — loads ALL rows into RAM first!
public IEnumerable<User> GetActiveUsers() =>
    _db.Users.AsEnumerable().Where(u => u.IsActive); // filter in C#

// ✅ IQueryable — SQL: SELECT * FROM Users WHERE IsActive = 1
public IQueryable<User> GetActiveUsers() =>
    _db.Users.Where(u => u.IsActive); // SQL WHERE clause

// Composing queries — each Where adds to the SQL
public async Task<List<UserDto>> SearchAsync(string name, int page)
{
    IQueryable<User> query = _db.Users.Where(u => u.IsActive);
    if (!string.IsNullOrEmpty(name))
        query = query.Where(u => u.Name.Contains(name));

    return await query
        .OrderBy(u => u.Name)
        .Skip((page - 1) * 20).Take(20)
        .Select(u => new UserDto(u.Id, u.Name))
        .ToListAsync(); // executes HERE
}
